import{_ as e,o as t,c as o,a2 as r}from"./chunks/framework.COr20JJv.js";const p=JSON.parse('{"title":"LyTools 项目介绍","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"projects/lytools/introduction.md","filePath":"projects/lytools/introduction.md"}'),l={name:"projects/lytools/introduction.md"};function i(n,a,s,h,u,d){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="lytools-项目介绍" tabindex="-1">LyTools 项目介绍 <a class="header-anchor" href="#lytools-项目介绍" aria-label="Permalink to &quot;LyTools 项目介绍&quot;">​</a></h1><blockquote><p>编辑日期：2026-03-22</p></blockquote><p>LyTools（栾媛小工具）是基于 <strong>Electron + Vue 3 + Element Plus</strong> 的桌面实用工具集，以插件形式扩展功能；代码在 <strong>GitHub、Gitee、GitCode</strong> 三端同步维护，可任选其一克隆与协作。</p><h2 id="许可" tabindex="-1">许可 <a class="header-anchor" href="#许可" aria-label="Permalink to &quot;许可&quot;">​</a></h2><p>以各仓库声明为准（例如 AGPL-3.0）。</p><h2 id="核心功能-插件示例" tabindex="-1">核心功能（插件示例） <a class="header-anchor" href="#核心功能-插件示例" aria-label="Permalink to &quot;核心功能（插件示例）&quot;">​</a></h2><h3 id="端口查杀" tabindex="-1">端口查杀 <a class="header-anchor" href="#端口查杀" aria-label="Permalink to &quot;端口查杀&quot;">​</a></h3><p>按端口查询占用进程并终止，支持 Windows / Linux。</p><h3 id="图标生成" tabindex="-1">图标生成 <a class="header-anchor" href="#图标生成" aria-label="Permalink to &quot;图标生成&quot;">​</a></h3><p>文字生成 ICO，自定义颜色、字体与形状，多尺寸预览与下载。</p><h3 id="加减混合" tabindex="-1">加减混合 <a class="header-anchor" href="#加减混合" aria-label="Permalink to &quot;加减混合&quot;">​</a></h3><p>低年级口算题生成，可导出 Excel 与打印。</p><h3 id="趣味与展示" tabindex="-1">趣味与展示 <a class="header-anchor" href="#趣味与展示" aria-label="Permalink to &quot;趣味与展示&quot;">​</a></h3><p>秀恩爱纪念日、养龙虾互动、锁屏 / 屏保类插件等。</p><h2 id="技术架构" tabindex="-1">技术架构 <a class="header-anchor" href="#技术架构" aria-label="Permalink to &quot;技术架构&quot;">​</a></h2><h3 id="桌面与界面" tabindex="-1">桌面与界面 <a class="header-anchor" href="#桌面与界面" aria-label="Permalink to &quot;桌面与界面&quot;">​</a></h3><ul><li><strong>桌面壳</strong>：Electron</li><li><strong>界面</strong>：Vue 3、Element Plus、Vite</li></ul><h3 id="插件与扩展" tabindex="-1">插件与扩展 <a class="header-anchor" href="#插件与扩展" aria-label="Permalink to &quot;插件与扩展&quot;">​</a></h3><p>插件目录：<code>~/.ly/tools/plugins</code>，可通过插件市场安装；主程序构建不包含插件时，由用户自行安装扩展。</p><h2 id="相关仓库" tabindex="-1">相关仓库 <a class="header-anchor" href="#相关仓库" aria-label="Permalink to &quot;相关仓库&quot;">​</a></h2><ul><li><a href="https://github.com/quxiangshun/ly-tools" target="_blank" rel="noreferrer">GitHub — quxiangshun/ly-tools</a></li><li><a href="https://gitee.com/quxiangshun/ly-tools" target="_blank" rel="noreferrer">Gitee — quxiangshun/ly-tools</a></li><li><a href="https://gitcode.com/quxiangshun/ly-tools" target="_blank" rel="noreferrer">GitCode — quxiangshun/ly-tools</a></li></ul><p>更多开发与构建步骤见 <a href="./quick-start.html">快速开始</a>。</p>',22)])])}const q=e(l,[["render",i]]);export{p as __pageData,q as default};
